"use client";

import { useCallback, useEffect, useState } from "react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { apiFetch } from "@/lib/api";
import type { SystemStatus } from "@/lib/types";

function formatValue(value: unknown) {
  if (value === null || value === undefined || value === "") return "Not configured";
  if (typeof value === "object") return JSON.stringify(value);
  return String(value);
}

export default function SystemStatusPage() {
  const [status, setStatus] = useState<SystemStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    setMessage("");

    try {
      const response = await apiFetch<{ data: SystemStatus }>("/api/system/status");
      setStatus(response.data);
    } catch (err) {
      setMessage(err instanceof Error ? err.message : "Unable to load system status");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  const healthy = status?.readiness.every((item) => item.status === "ok") ?? false;

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 md:flex-row md:items-end md:justify-between">
        <div>
          <p className="text-sm uppercase text-muted-foreground">Operations</p>
          <h1 className="text-3xl font-semibold">System Status</h1>
          <p className="mt-2 text-sm text-muted-foreground">
            Service readiness and runtime health for the Lumentix workspace.
          </p>
        </div>
        <Button type="button" variant="outline" onClick={load} disabled={loading}>
          {loading ? "Checking..." : "Refresh"}
        </Button>
      </div>

      {message ? <p className="rounded-lg border border-red-300 bg-red-50 p-3 text-sm text-red-900 dark:border-red-500/40 dark:bg-red-500/15 dark:text-red-200">{message}</p> : null}

      <section className="rounded-lg border border-border bg-background p-5 shadow-soft">
        <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
          <div>
            <h2 className="text-base font-semibold">{status?.service ?? "LUMENTIX HRFLOW"}</h2>
            <p className="mt-1 text-sm text-muted-foreground">
              Last checked: {status ? new Date(status.generated_at).toLocaleString() : "Pending"}
            </p>
          </div>
          <Badge variant={healthy ? "teal" : "amber"}>{healthy ? "Ready" : "Needs Attention"}</Badge>
        </div>
      </section>

      <section className="rounded-lg border border-border bg-background shadow-soft">
        <div className="border-b border-border p-5">
          <h2 className="text-base font-semibold">Readiness Checks</h2>
        </div>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Check</TableHead>
              <TableHead>Status</TableHead>
              <TableHead>Detail</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {loading && !status ? (
              <TableRow>
                <TableCell colSpan={3} className="text-center text-muted-foreground">
                  Checking system status...
                </TableCell>
              </TableRow>
            ) : (
              status?.readiness.map((item) => (
                <TableRow key={item.key}>
                  <TableCell className="font-medium">{item.label}</TableCell>
                  <TableCell>
                    <Badge variant={item.status === "ok" ? "teal" : "amber"}>{item.status === "ok" ? "OK" : "Attention"}</Badge>
                  </TableCell>
                  <TableCell className="text-muted-foreground">{item.detail}</TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </section>

      {status ? (
        <div className="grid gap-4 lg:grid-cols-2">
          <section className="rounded-lg border border-border bg-background shadow-soft">
            <div className="border-b border-border p-5">
              <h2 className="text-base font-semibold">Database</h2>
            </div>
            <div className="space-y-3 p-5 text-sm">
              <Info label="Driver" value={status.database.driver} />
              <Info label="Project ID" value={status.database.project_id} />
              <Info label="Local Test Host" value={status.database.emulator_host ?? "Not active"} />
              <Info label="Health" value={formatValue(status.database.health)} />
            </div>
          </section>

          <section className="rounded-lg border border-border bg-background shadow-soft">
            <div className="border-b border-border p-5">
              <h2 className="text-base font-semibold">Storage And Public Links</h2>
            </div>
            <div className="space-y-3 p-5 text-sm">
              <Info label="Storage Driver" value={status.storage.driver} />
              <Info label="Storage Directory" value={status.storage.local_directory ?? "Not configured"} />
              <Info label="Public Link Base URL" value={status.verification.public_verify_base_url} />
              <Info label="Allowed Frontend Origins" value={status.verification.frontend_origins.join(", ")} />
            </div>
          </section>

          <section className="rounded-lg border border-border bg-background shadow-soft lg:col-span-2">
            <div className="border-b border-border p-5">
              <h2 className="text-base font-semibold">Email Delivery</h2>
            </div>
            <div className="space-y-3 p-5 text-sm">
              <Info label="SMTP Status" value={status.email.smtp_configured ? "Configured" : status.email.host ? "Needs credentials" : "Disabled"} />
              <Info label="SMTP Host" value={status.email.host ?? "Not configured"} />
              <Info label="SMTP Port" value={String(status.email.port)} />
              <Info label="SMTP User" value={status.email.user ?? "Not configured"} />
              <Info label="Sender" value={status.email.from} />
            </div>
          </section>
        </div>
      ) : null}

      {status ? (
        <section className="rounded-lg border border-border bg-background p-5 shadow-soft">
          <h2 className="text-base font-semibold">Data Collections</h2>
          <div className="mt-4 flex flex-wrap gap-2">
            {status.database.collections.map((collection) => (
              <Badge key={collection} variant="muted">{collection}</Badge>
            ))}
          </div>
        </section>
      ) : null}
    </div>
  );
}

function Info({ label, value }: { label: string; value: string }) {
  return (
    <div className="grid gap-1 border-b border-border pb-3 last:border-b-0 last:pb-0">
      <span className="text-xs uppercase text-muted-foreground">{label}</span>
      <span className="break-words font-medium">{value}</span>
    </div>
  );
}
